INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('招聘经理 - 湘潭（社招）', '制造', '湘潭', '民营企业', 8000, 12000, '1. 熟练使用 ATS 等招聘管理系统，具备招聘全流程管理能力； 2. 熟练使用办公软件，具备招聘数据统计、分析与复盘能力； 3. 具备招聘体系搭建与优化能力。', '1. 具备优秀的沟通协调能力与跨部门协作能力； 2. 具备较强的团队管理能力与带教能力； 3. 目标感强，具备较强的执行力与抗压能力，能适应出差。', 0, '一般', '1. 根据公司业务发展规划和人才需求，制定年度 / 季度招聘计划、预算及渠道策略； 2. 设计并持续优化从职位发布、候选人筛选、面试到录用的全流程，提升招聘效率与候选人体验； 3. 负责 ATS（申请人跟踪系统）等招聘工具的选择、维护与数据管理； 4. 与业务部门负责人沟通，明确岗位职责、任职要求及团队文化匹配度； 5. 管理并拓展招聘渠道（如猎头、招聘网站、校园招聘、内部推荐、社交媒体等），建立人才储备库； 6. 组织简历筛选、电话面试、协调面试安排，参与核心岗位面试并评估候选人； 7. 管理背调流程，协调薪酬谈判，发放录用通知，确保入职流程顺利； 8. 管理招聘专员 / 助理，分配任务，提供培训与指导，提升团队专业能力； 9. 跟踪并分析招聘关键指标（如平均招聘周期、人均招聘成本、录用率、留存率等），定期输出报告； 10. 基于数据发现流程瓶颈或效率问题，提出改进方案并推动实施。', '招聘全流程执行, 渠道拓展与运营, 校招项目运营, 简历筛选与面试, 招聘数据分析', '本科及以上', '人力资源管理、工商管理等人事相关专业优先', '3-5 年工作经验，3-5 年招聘经历，同岗位经历 2 年以上', '社招（应届生可投）', '1. 有人力资源管理师相关证书； 2. 有制造业 / 汽车行业招聘管理经验。', '8000-12000 元 / 月', '46112', NULL, 'BOSS直聘获取', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('招聘经理 - 连云港（社招）', '其他', '连云港', '民营企业', 9000, 14000, '1. 熟悉全品类招聘流程、方法与各类招聘渠道工具； 2. 具备招聘数据统计、分析与优化能力； 3. 熟练使用办公软件，具备招聘方案制定能力。', '1. 具备优秀的领导能力与团队管理、带教能力； 2. 具备良好的沟通协调能力与跨方对接能力； 3. 具备创新意识，结果导向，多任务处理能力强，抗压能力优秀。', 0, '一般', '1. 掌握招聘专业知识：熟悉招聘流程和方法，了解各种招聘渠道和工具，能够制定有效的招聘策略； 2. 具备良好的沟通能力：能够与候选人、部门经理等各方有效沟通，建立良好的关系； 3. 具备领导能力：能够指导招聘团队成员，协调工作，推动招聘目标的实现； 4. 具备分析能力：能够分析招聘数据和趋势，优化招聘流程和策略； 5. 具备创新意识：能够不断尝试新的招聘方法和工具，提升招聘效率和质量； 6. 结果导向：注重招聘目标的实现，能够设定明确的指标和目标，并通过数据分析评估招聘效果； 7. 多任务处理能力：能够同时处理多个招聘项目，有效管理时间和资源，保证招聘工作的顺利进行。', '招聘全流程执行, 渠道拓展与运营, 招聘数据分析, 简历筛选与面试', '大专及以上', '人力资源管理、心理学、管理学等相关专业优先', '3-5 年工作经验，3 年以上招聘相关管理工作经验，有招聘团队管理经验', '社招（应届生可投）', '1. 有人力资源管理师相关证书； 2. 有线下零售 / 高管招聘经验。', '9000-14000 元 / 月', '46112', NULL, 'BOSS直聘获取', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('培训实习生 - 北京（实习）', '互联网 / IT', '北京', '民营企业', 150, 180, '1. 熟练使用Office办公软件；2. 具备基础的文案排版、海报制作能力；3. 具备培训项目执行与数据统计能力', '1. 工作认真负责，善于沟通；2. 具备强烈的责任心和团队合作精神；3. 思维活跃有创意', 1, '极度友好', '1. 参与专业及通用力培训项目，包括资源沟通、宣传运营、物料筹备、数据统计等；2. 支持微信公众号及内部广播号运营，包括文章排版、海报制作、活动设计、社群维护等', 'OD 组织发展支持', '不限', '人力资源管理、教育学、心理学等相关专业优先', '大三、研一、研二在校生，每周出勤4天及以上，可实习3个月优先', '日常实习', '1. 有公众号运营经验；2. 有视频/海报制作经验', '150-180元/天', '46093', '46331', 'https://www.shixiseng.com/intern/inn_uq0bfhs4dj7n?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训实习岗 - 深圳（实习）', '医疗健康 / 生物制药', '深圳', '民营企业', 200, 300, '1. 具备专业的中文书面表达能力，可完成多场景文案撰写；2. 熟练使用Word、Excel、PowerPoint等办公软件；3. 具备基础的数据分析与逻辑梳理能力', '1. 出色的逻辑思维与分析能力，注重细节和准确性；2. 积极主动，乐于学习和承担任务；3. 良好的沟通协作能力，可高效配合团队完成工作；4. 责任心强，做事细致严谨', 1, '极度友好', '1. 内容制作与信息梳理：协助撰写内部通告、项目说明、邮件及知识总结文案，梳理提炼会议/访谈资料，形成结构化报告，校对优化学习资料；2. 项目运营管理：协助人才发展项目日常运营，含学员通知、平台操作、物料准备、数据收集，维护培训信息管理系统/在线学习平台内容；3. 活动组织协助：支持内部培训、工作坊、员工活动的前期筹备、现场协调及后期跟进；4. 跨文化沟通支持：为国际项目提供沟通或文档支持，输出多元视角建议；5. 数据分析与报告：协助收集整理培训反馈/调研数据，制作基础数据可视化报告', 'OD 组织发展支持', '本科及以上', '人文社科、新闻传播、商科、教育学、管理学、心理学等专业优先', '本科大三/大四、硕士在读，可实习4个月，每周到岗5天', '日常实习', '1. 熟悉Canva、PS、AI等平面设计工具；2. 具备摄影、视频剪辑、H5制作能力；3. 有海外留学/交换生等国际生活学习背景', '200-300元/天', '46015', '46294', 'https://www.shixiseng.com/intern/inn_e6g8gzm0zjne?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训实习生 - 深圳（实习）', '制造', '深圳', '股份制企业', 180, 250, '1. 掌握基础拍摄技巧，可使用剪映、Premiere完成简单剪辑；2. 熟练使用Office办公软件；3. 具备基础的视频剪辑、素材采集与后期处理能力', '1. 可独立完成素材采集、后期处理，保障内容视觉呈现效果；2. 做事认真负责，踏实上进，具备较强的学习能力与策划执行能力', 1, '极度友好', '1. 协助培训全流程落地，完成训前场地/物料/流程准备、训中现场支持、训后反馈收集与培训Vlog制作；2. 跟进培训项目进度、会议安排、线上学习平台运营；3. 协助完成物料采购、票据报销、流程申请与对接；4. 培训资料整理、打印，培训数据筛选、汇总；5. 整理项目宣发资料，含案例、活动内容、宣传视频等；6. 协助策划线上线下品牌宣传活动', 'OD 组织发展支持', '本科及以上', '广告、传媒等相关专业优先', '2026届本科及以上在校生，可连续实习6个月以上，每周出勤4-5天', '日常实习', '1. 有相关视频/设计作品；2. 有活动策划、新媒体运营经验', '180-250元/天', '46001', '46262', 'https://www.shixiseng.com/intern/inn_kmkef5xovere?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）');